    inlineSchema: `generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

enum UserRole {
  USER
  EDITOR
  ADMIN
}

enum UserStatus {
  ACTIVE
  INACTIVE
  SUSPENDED
}

enum ComicStatus {
  DRAFT
  PUBLISHED
  ARCHIVED
}

enum ComicAvailability {
  AVAILABLE
  UNAVAILABLE
  COMING_SOON
}

model User {
  id           String     @id @default(uuid()) @db.Uuid
  firstName    String     @map("first_name")
  lastName     String     @map("last_name")
  username     String     @unique
  email        String     @unique
  passwordHash String     @map("password_hash")
  role         UserRole   @default(USER)
  status       UserStatus @default(ACTIVE)
  avatarUrl    String?    @map("avatar_url")
  lastLoginAt  DateTime?  @map("last_login_at")
  createdAt    DateTime   @default(now()) @map("created_at")
  updatedAt    DateTime   @updatedAt @map("updated_at")
  deletedAt    DateTime?  @map("deleted_at")

  sessions  Session[]
  comics    Comic[]
  favorites Favorite[]
  auditLogs AuditLog[]

  @@index([email])
  @@index([username])
  @@map("users")
}

model Session {
  id               String    @id @default(uuid()) @db.Uuid
  userId           String    @map("user_id") @db.Uuid
  refreshTokenHash String    @map("refresh_token_hash")
  userAgent        String?   @map("user_agent")
  ipAddress        String?   @map("ip_address")
  expiresAt        DateTime  @map("expires_at")
  revokedAt        DateTime? @map("revoked_at")
  createdAt        DateTime  @default(now()) @map("created_at")
  updatedAt        DateTime  @updatedAt @map("updated_at")

  user User @relation(fields: [userId], references: [id], onDelete: Cascade)

  @@index([userId])
  @@index([refreshTokenHash])
  @@map("sessions")
}

model ComicType {
  id          String    @id @default(uuid()) @db.Uuid
  name        String    @unique
  slug        String    @unique
  description String?
  isActive    Boolean   @default(true) @map("is_active")
  createdAt   DateTime  @default(now()) @map("created_at")
  updatedAt   DateTime  @updatedAt @map("updated_at")
  deletedAt   DateTime? @map("deleted_at")

  comics Comic[]

  @@index([slug])
  @@map("comic_types")
}

model Comic {
  id              String            @id @default(uuid()) @db.Uuid
  title           String
  slug            String            @unique
  originalTitle   String?           @map("original_title")
  description     String?
  synopsis        String?
  author          String
  illustrator     String?
  publisher       String?
  publicationYear Int               @map("publication_year")
  issueNumber     Int?              @map("issue_number")
  totalPages      Int?              @map("total_pages")
  language        String?           @default("es")
  isbn            String?           @unique
  coverImageUrl   String?           @map("cover_image_url")
  comicTypeId     String            @map("comic_type_id") @db.Uuid
  status          ComicStatus       @default(DRAFT)
  availability    ComicAvailability @default(AVAILABLE)
  isFeatured      Boolean           @default(false) @map("is_featured")
  country         String?
  ageRating       String?           @map("age_rating")
  edition         String?
  volume          Int?
  seriesName      String?           @map("series_name")
  externalUrl     String?           @map("external_url")
  createdById     String            @map("created_by_id") @db.Uuid
  createdAt       DateTime          @default(now()) @map("created_at")
  updatedAt       DateTime          @updatedAt @map("updated_at")
  publishedAt     DateTime?         @map("published_at")
  deletedAt       DateTime?         @map("deleted_at")

  comicType ComicType  @relation(fields: [comicTypeId], references: [id])
  createdBy User       @relation(fields: [createdById], references: [id])
  favorites Favorite[]

  @@index([title])
  @@index([slug])
  @@index([author])
  @@index([publisher])
  @@index([status])
  @@index([availability])
  @@index([comicTypeId])
  @@index([createdAt])
  @@map("comics")
}

model Favorite {
  id        String   @id @default(uuid()) @db.Uuid
  userId    String   @map("user_id") @db.Uuid
  comicId   String   @map("comic_id") @db.Uuid
  createdAt DateTime @default(now()) @map("created_at")

  user  User  @relation(fields: [userId], references: [id], onDelete: Cascade)
  comic Comic @relation(fields: [comicId], references: [id], onDelete: Cascade)

  @@unique([userId, comicId])
  @@index([userId])
  @@index([comicId])
  @@map("favorites")
}

model AuditLog {
  id        String   @id @default(uuid()) @db.Uuid
  userId    String?  @map("user_id") @db.Uuid
  action    String
  entity    String
  entityId  String?  @map("entity_id")
  metadata  Json?
  ipAddress String?  @map("ip_address")
  userAgent String?  @map("user_agent")
  createdAt DateTime @default(now()) @map("created_at")

  user User? @relation(fields: [userId], references: [id], onDelete: SetNull)

  @@index([userId])
  @@index([action])
  @@index([entity])
  @@index([createdAt])
  @@map("audit_logs")
}
`,
