// src/services/auth.service.ts
class AuthService {
  userSelect = {
    id: true,
    firstName: true,
    lastName: true,
    username: true,
    email: true,
    role: true,
    status: true,
    avatarUrl: true,
    createdAt: true
  };
  async register(input, ipAddress, userAgent) {
    const existingEmail = await database_default.user.findUnique({
      where: { email: input.email }
    });
    if (existingEmail) {
      throw new ConflictError("El correo electr\xF3nico ya se encuentra registrado");
    }
    const existingUsername = await database_default.user.findUnique({
      where: { username: input.username }
    });
    if (existingUsername) {
      throw new ConflictError("El nombre de usuario ya se encuentra registrado");
    }
    const passwordHash = await Bun.password.hash(input.password, {
      algorithm: "argon2id",
      memoryCost: 19456,
      timeCost: 2
    });
    const user = await database_default.user.create({
      data: {
        firstName: input.firstName,
        lastName: input.lastName,
        username: input.username,
        email: input.email,
        passwordHash,
        role: "USER",
        status: "ACTIVE"
      },
      select: this.userSelect
    });
    const session = await database_default.session.create({
      data: {
        userId: user.id,
        refreshTokenHash: "",
        expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000)
      }
    });
    const tokens = await tokenService.generateTokens({
      sub: user.id,
      email: user.email,
      role: user.role,
      sessionId: session.id
    });
    const refreshTokenHash = await tokenService.hashToken(tokens.refreshToken);
    await database_default.session.update({
      where: { id: session.id },
      data: {
        refreshTokenHash,
        ipAddress: ipAddress || null,
        userAgent: userAgent || null
      }
    });
    await auditService.log({
      userId: user.id,
      action: "USER_REGISTERED" /* USER_REGISTERED */,
      entity: "User",
      entityId: user.id,
      ipAddress,
      userAgent
    });
    return {
      accessToken: tokens.accessToken,
      refreshToken: tokens.refreshToken,
      user: this.toUserPublic(user)
    };
  }
  async login(input, ipAddress, userAgent) {
    const user = await database_default.user.findUnique({
      where: { email: input.email }
    });
    if (!user) {
      throw new UnauthorizedError("Credenciales inv\xE1lidas");
    }
    if (user.deletedAt) {
      throw new UnauthorizedError("Credenciales inv\xE1lidas");
    }
    if (user.status === "SUSPENDED") {
      throw new ForbiddenError("Tu cuenta ha sido suspendida. Contacta al administrador.");
    }
    if (user.status === "INACTIVE") {
      throw new ForbiddenError("Tu cuenta est\xE1 inactiva. Contacta al administrador.");
    }
    const validPassword = await Bun.password.verify(input.password, user.passwordHash);
    if (!validPassword) {
      throw new UnauthorizedError("Credenciales inv\xE1lidas");
    }
    await database_default.user.update({
      where: { id: user.id },
      data: { lastLoginAt: new Date }
    });
    const session = await database_default.session.create({
      data: {
        userId: user.id,
        refreshTokenHash: "",
        expiresAt: tokenService.parseExpiresIn(),
        ipAddress: ipAddress || null,
        userAgent: userAgent || null
      }
    });
    const tokens = await tokenService.generateTokens({
      sub: user.id,
      email: user.email,
      role: user.role,
      sessionId: session.id
    });
    const refreshTokenHash = await tokenService.hashToken(tokens.refreshToken);
    await database_default.session.update({
      where: { id: session.id },
      data: { refreshTokenHash }
    });
    await auditService.log({
      userId: user.id,
      action: "USER_LOGIN" /* USER_LOGIN */,
      entity: "User",
      entityId: user.id,
      ipAddress,
      userAgent
    });
    return {
      accessToken: tokens.accessToken,
      refreshToken: tokens.refreshToken,
      user: this.toUserPublic(user)
    };
  }
  async refresh(refreshToken, ipAddress, userAgent) {
    let payload;
    try {
      payload = await tokenService.verifyRefresh(refreshToken);
    } catch {
      throw new UnauthorizedError("Refresh token inv\xE1lido o expirado");
    }
    const session = await database_default.session.findUnique({
      where: { id: payload.sessionId },
      include: { user: true }
    });
    if (!session) {
      throw new UnauthorizedError("Sesi\xF3n no encontrada");
    }
    if (session.revokedAt) {
      await database_default.session.updateMany({
        where: { userId: session.userId },
        data: { revokedAt: new Date }
      });
      throw new UnauthorizedError("Sesi\xF3n revocada");
    }
    if (session.expiresAt < new Date) {
      throw new UnauthorizedError("Sesi\xF3n expirada");
    }
    const validHash = await tokenService.verifyTokenHash(refreshToken, session.refreshTokenHash);
    if (!validHash) {
      throw new UnauthorizedError("Refresh token inv\xE1lido");
    }
    if (session.user.status === "SUSPENDED") {
      throw new ForbiddenError("Cuenta suspendida");
    }
    if (session.user.deletedAt) {
      throw new UnauthorizedError("Cuenta no encontrada");
    }
    await database_default.session.update({
      where: { id: session.id },
      data: { revokedAt: new Date }
    });
    const newSession = await database_default.session.create({
      data: {
        userId: session.userId,
        refreshTokenHash: "",
        expiresAt: tokenService.parseExpiresIn(),
        ipAddress: ipAddress || null,
        userAgent: userAgent || null
      }
    });
    const tokens = await tokenService.generateTokens({
      sub: session.user.id,
      email: session.user.email,
      role: session.user.role,
      sessionId: newSession.id
    });
    const newHash = await tokenService.hashToken(tokens.refreshToken);
    await database_default.session.update({
      where: { id: newSession.id },
      data: { refreshTokenHash: newHash }
    });
    return {
      accessToken: tokens.accessToken,
      refreshToken: tokens.refreshToken,
      user: this.toUserPublic(session.user)
    };
  }
  async logout(sessionId, userId, ipAddress, userAgent) {
    await database_default.session.updateMany({
      where: { id: sessionId, userId, revokedAt: null },
      data: { revokedAt: new Date }
    });
    await auditService.log({
      userId,
      action: "USER_LOGOUT" /* USER_LOGOUT */,
      entity: "Session",
      entityId: sessionId,
      ipAddress,
      userAgent
    });
  }
  async logoutAll(userId, ipAddress, userAgent) {
    const sessions = await database_default.session.updateMany({
      where: { userId, revokedAt: null },
      data: { revokedAt: new Date }
    });
    await auditService.log({
      userId,
      action: "USER_LOGOUT" /* USER_LOGOUT */,
      entity: "User",
      entityId: userId,
      metadata: { sessionsRevoked: sessions.count },
      ipAddress,
      userAgent
    });
  }
  async getMe(userId) {
    const user = await database_default.user.findUnique({
      where: { id: userId },
      select: this.userSelect
    });
    if (!user || await this.isDeleted(userId)) {
      throw new NotFoundError3("Usuario no encontrado");
    }
    return this.toUserPublic(user);
  }
  async isDeleted(userId) {
    const user = await database_default.user.findUnique({
      where: { id: userId },
      select: { deletedAt: true }
    });
    return user?.deletedAt !== null;
  }
  toUserPublic(user) {
    return {
      id: user.id,
      firstName: user.firstName,
      lastName: user.lastName,
      username: user.username,
      email: user.email,
      role: user.role,
      status: user.status,
      avatarUrl: user.avatarUrl || null,
      createdAt: user.createdAt.toISOString()
    };
  }
}
var authService = new AuthService;

// src/utils/api-response.ts
function apiSuccess(message, data, pagination) {
  return {
    success: true,
    message,
    data,
    ...pagination ? { pagination } : {}
  };
}
function apiError(message, errors2) {
  return {
    success: false,
    message,
    ...errors2 ? { errors: errors2 } : {}
  };
}
function paginationInfo(page, limit, total) {
  const totalPages = Math.ceil(total / limit);
  return {
    page,
    limit,
    total,
    totalPages,
    hasNextPage: page < totalPages,
    hasPreviousPage: page > 1
  };
}

// src/controllers/auth.controller.ts
class AuthController {
  async register({ body, request }) {
    const ip = request.headers.get("x-forwarded-for") || "unknown";
    const ua = request.headers.get("user-agent") || undefined;
    const result = await authService.register(body, ip, ua);
    return apiSuccess("Usuario registrado exitosamente", result);
  }
  async login({ body, request }) {
    const ip = request.headers.get("x-forwarded-for") || undefined;
    const ua = request.headers.get("user-agent") || undefined;
    const result = await authService.login(body, ip, ua);
    return apiSuccess("Inicio de sesi\xF3n exitoso", result);
  }
  async refresh({ body, request }) {
    const ip = request.headers.get("x-forwarded-for") || undefined;
    const ua = request.headers.get("user-agent") || undefined;
    const result = await authService.refresh(body.refreshToken, ip, ua);
    return apiSuccess("Sesi\xF3n renovada exitosamente", result);
  }
  async logout({ user, request }) {
    const ip = request.headers.get("x-forwarded-for") || undefined;
    const ua = request.headers.get("user-agent") || undefined;
    await authService.logout(user.sessionId, user.id, ip, ua);
    return apiSuccess("Sesi\xF3n cerrada exitosamente", null);
  }
  async logoutAll({ user, request }) {
    const ip = request.headers.get("x-forwarded-for") || undefined;
    const ua = request.headers.get("user-agent") || undefined;
    await authService.logoutAll(user.id, ip, ua);
    return apiSuccess("Sesiones cerradas exitosamente", null);
  }
  async me({ user }) {
    const profile = await authService.getMe(user.id);
    return apiSuccess("Perfil obtenido exitosamente", profile);
  }
  async health() {
    return apiSuccess("Servicio disponible", {
      status: "healthy",
      environment: "development",
      database: "connected",
      timestamp: new Date().toISOString()
    });
  }
}
var authController = new AuthController;

// src/middlewares/auth.middleware.ts
var authMiddleware = (app) => app.derive(async ({ headers, request }) => {
  const authHeader = headers["authorization"];
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    throw new UnauthorizedError("Token de acceso no proporcionado");
  }
  const token = authHeader.slice(7);
  try {
    const payload = await verifyAccessToken(token);
    const user = {
      id: payload.sub,
      email: payload.email,
      role: payload.role,
      sessionId: payload.sessionId
    };
    return { user };
  } catch (error) {
    if (error instanceof UnauthorizedError)
      throw error;
    const message = error.message === "Token expirado" ? "Token expirado" : "Token inv\xE1lido";
    throw new UnauthorizedError(message);
  }
});

