// src/services/comic-type.service.ts
class ComicTypeService {
  async getAll(isActiveOnly = false) {
    const where = { deletedAt: null };
    if (isActiveOnly) {
      where.isActive = true;
    }
    return database_default.comicType.findMany({
      where,
      orderBy: { name: "asc" }
    });
  }
  async getBySlug(slug) {
    const comicType = await database_default.comicType.findUnique({
      where: { slug }
    });
    if (!comicType || comicType.deletedAt) {
      throw new NotFoundError3("Tipo de c\xF3mic no encontrado");
    }
    return comicType;
  }
  async getById(id) {
    const comicType = await database_default.comicType.findUnique({
      where: { id }
    });
    if (!comicType || comicType.deletedAt) {
      throw new NotFoundError3("Tipo de c\xF3mic no encontrado");
    }
    return comicType;
  }
  async create(data, userId, ipAddress, userAgent) {
    const slug = slugify(data.name);
    const existing = await database_default.comicType.findUnique({
      where: { slug }
    });
    if (existing) {
      throw new ConflictError("Ya existe un tipo de c\xF3mic con ese nombre");
    }
    const comicType = await database_default.comicType.create({
      data: {
        name: data.name,
        slug,
        description: data.description || null
      }
    });
    await auditService.log({
      userId,
      action: "COMIC_TYPE_CREATED" /* COMIC_TYPE_CREATED */,
      entity: "ComicType",
      entityId: comicType.id,
      metadata: { name: comicType.name },
      ipAddress,
      userAgent
    });
    return comicType;
  }
  async update(id, data, userId, ipAddress, userAgent) {
    await this.getById(id);
    if (data.name) {
      const slug = slugify(data.name);
      const existing = await database_default.comicType.findFirst({
        where: { slug, id: { not: id } }
      });
      if (existing) {
        throw new ConflictError("Ya existe un tipo de c\xF3mic con ese nombre");
      }
    }
    const updateData = {};
    if (data.name) {
      updateData.name = data.name;
      updateData.slug = slugify(data.name);
    }
    if (data.description !== undefined) {
      updateData.description = data.description;
    }
    const comicType = await database_default.comicType.update({
      where: { id },
      data: updateData
    });
    await auditService.log({
      userId,
      action: "COMIC_TYPE_UPDATED" /* COMIC_TYPE_UPDATED */,
      entity: "ComicType",
      entityId: id,
      metadata: { name: comicType.name },
      ipAddress,
      userAgent
    });
    return comicType;
  }
  async toggleStatus(id, isActive) {
    await this.getById(id);
    return database_default.comicType.update({
      where: { id },
      data: { isActive }
    });
  }
  async delete(id, userId) {
    await this.getById(id);
    const comicsCount = await database_default.comic.count({
      where: { comicTypeId: id, deletedAt: null }
    });
    if (comicsCount > 0) {
      await database_default.comicType.update({
        where: { id },
        data: { isActive: false, deletedAt: new Date }
      });
    } else {
      await database_default.comicType.update({
        where: { id },
        data: { deletedAt: new Date }
      });
    }
  }
}
