var checkRole = (role) => {
  return (ctx) => {
    if (!ctx.user) {
      ctx.set.status = 401;
      return { success: false, message: "No autorizado" };
    }
    if (ctx.user.role !== role && ctx.user.role !== "ADMIN") {
      if (role === "ADMIN") {
        ctx.set.status = 403;
        return {
          success: false,
          message: "No tienes permisos para realizar esta acci\xF3n"
        };
      }
      if (role === "EDITOR" && ctx.user.role !== "EDITOR") {
        ctx.set.status = 403;
        return {
          success: false,
          message: "No tienes permisos para realizar esta acci\xF3n"
        };
      }
    }
  };
};
