// src/middlewares/error.middleware.ts
var import_client2 = __toESM(require_default2(), 1);
var errorMiddleware = (app) => app.onError(({ error, set }) => {
  if (error instanceof ApiError) {
    set.status = error.statusCode;
    return apiError(error.message, error.errors);
  }
  if (error instanceof import_client2.Prisma.PrismaClientKnownRequestError) {
    if (error.code === "P2002") {
      const target = error.meta?.target || [];
      set.status = 409;
      return apiError(`El valor ya existe: ${target.join(", ")}`, target.map((field) => ({
        field,
        message: `El campo ${field} ya se encuentra registrado`
      })));
    }
    if (error.code === "P2025") {
      set.status = 404;
      return apiError("Registro no encontrado");
    }
    if (error.code === "P2003") {
      set.status = 400;
      return apiError("Referencia inv\xE1lida");
    }
  }
  if (error instanceof import_client2.Prisma.PrismaClientValidationError) {
    set.status = 400;
    return apiError("Datos inv\xE1lidos enviados a la base de datos");
  }
  const errorObj = error;
  const message = config2.nodeEnv === "production" ? "Error interno del servidor" : errorObj.message || "Error interno del servidor";
  set.status = 500;
  console.error(`[ERROR] ${errorObj.message || error}`);
  return apiError(message);
});

// src/middlewares/not-found.middleware.ts
var notFoundMiddleware = (app) => app.onError(({ code, set }) => {
  if (code === "NOT_FOUND") {
    set.status = 404;
    return apiError("Ruta no encontrada");
  }
});

// src/middlewares/request-logger.middleware.ts
var requestLoggerMiddleware = (app) => app.onRequest(({ request }) => {
  if (config2.logLevel === "debug") {
    const url = new URL(request.url);
    console.log(`[${request.method}] ${url.pathname}`);
  }
});

